                render(skipSave = false) {
                    this.$container.empty();
                    this.tags.forEach((tag, index) => {
                        const $chip = $(`<div class="cet-chip active-tag"><span>${_.escape(tag)}</span><div class="cet-chip-del"><i class="fa-solid fa-times"></i></div></div>`);
                        $chip.find('.cet-chip-del').on('click', () => {
                            this.tags.splice(index, 1);
                            this.render();
                        });
                        this.$container.append($chip);
                    });
                    // Store real value in data attribute for save logic
                    this.updateState(skipSave);
                }

                add(tag) {
                    tag = tag.replace(/[,，]+$/, '').trim();
                    if (!tag) return;
                    if (!this.tags.includes(tag)) {
                        this.tags.push(tag);
                        this.render();
                    }
                    this.updateState();
                }

                updateState(skipSave = false) {
                    const currentInput = this.$input.val().trim();
                    const combined = [...this.tags];
                    if (currentInput && !combined.includes(currentInput)) {
                        // Don't add to array permanently, just for the "data-val" used by export
                        combined.push(currentInput);
                    }
                    this.$input.data('real-value', combined.join(', '));
                    // Call safe save function
                    if (!skipSave) saveCurrentState();
                }

                clear() {
                    this.tags = [];
                    this.render();
                    this.$input.val('');
                    this.updateState();
                }

                bindEvents() {
                    this.$input.on('keydown', (e) => {
                        if (e.which === 32 || e.which === 13) { // Space or Enter
                            e.preventDefault();
                            const val = this.$input.val().trim();
                            if (val) {
